-- ---------------------------------------------------------- Tabel structuur voor tabel beloningtabel-- --------------------------------------------------------DROP TABLE IF EXISTS beloningtabel;CREATE TABLE beloningtabel ( beloning_id int(11) NOT NULL auto_increment, persoon_id int(11) NOT NULL default '0', beloning_categorie varchar(30) default NULL, beloning_text varchar(160) default NULL, beloning_gewicht smallint(4) default NULL,PRIMARY KEY (beloning_id), KEY persoon_id (persoon_id)) TYPE=MyISAM AUTO_INCREMENT=1000 ;-- Gegevens worden uitgevoerd voor tabel beloningtabel--
